const message = $input.item.json.message;
if (!message) return [];

const text = message.text || '';
const chatId = message.chat.id;
const messageId = message.message_id;

// 1. Seguridad: solo Antonio Polanco
if (chatId !== 724801911) {
  return []; // Ignorar silenciosamente
}

function reply(text) {
  return {
    json: {
      action: 'reply',
      chatId,
      replyToMessageId: messageId,
      text,
      parseMode: 'Markdown'
    }
  };
}

// 2. Ayuda e Inicio
if (text.startsWith('/start') || text.startsWith('/help') || !text.startsWith('/tarea')) {
  const helpMessage = `📝 *Cómo asignar tareas a tus agentes:*
Usa el siguiente formato:
\`/tarea [agente]: [instrucción]\`

🤖 *Agentes disponibles (usa el alias):*
- *cto*: CTO Agent
- *n8n* o *automation*: n8n Automation Agent
- *reporting* o *reportes*: Reporting Agent
- *devops*: DevOps Agent
- *cos* o *chief*: Chief of Staff Agent
- *whatsapp* o *wa*: WhatsApp Business Agent
- *ceo*: CEO Agent

💡 *Ejemplo:*
\`/tarea cto: Escribe un script en Python para limpiar la base de datos.\``;
  return [reply(helpMessage)];
}

// 3. Expresión regular para parsear comando
const match = text.match(/^\/tarea\s+(\w+)\s*:\s*(.+)$/is);
if (!match) {
  return [reply(`⚠️ *Formato incorrecto.*
Usa: \`/tarea [agente]: [instrucción]\`

Ejemplo: \`/tarea cto: Crear copia de seguridad.\``)];
}

const agentAlias = match[1].toLowerCase().trim();
const instruction = match[2].trim();

const agentMap = {
  'cto': '19948f90-95d4-4cb1-afd7-9ff64450fdf0',
  'n8n': 'df330bdb-7956-4a34-a8c8-5e2df95c14e9',
  'automation': 'df330bdb-7956-4a34-a8c8-5e2df95c14e9',
  'automatizacion': 'df330bdb-7956-4a34-a8c8-5e2df95c14e9',
  'reporting': '3c88bb29-c1d9-4358-aa4c-50c32bccc8f4',
  'reportes': '3c88bb29-c1d9-4358-aa4c-50c32bccc8f4',
  'devops': 'e895240c-8524-403a-8770-d095915d8302',
  'cos': '9819d4cb-e0b7-45d8-8e26-b257298aac79',
  'chief': '9819d4cb-e0b7-45d8-8e26-b257298aac79',
  'staff': '9819d4cb-e0b7-45d8-8e26-b257298aac79',
  'whatsapp': '876bad48-2bd7-4dd4-a429-6bf95f6a94f6',
  'wa': '876bad48-2bd7-4dd4-a429-6bf95f6a94f6',
  'comercial': '876bad48-2bd7-4dd4-a429-6bf95f6a94f6',
  'ceo': 'b713f1b8-1b78-486c-b6ef-0fc2a885f2ec'
};

const agentMapNames = {
  '19948f90-95d4-4cb1-afd7-9ff64450fdf0': 'CTO Agent',
  'df330bdb-7956-4a34-a8c8-5e2df95c14e9': 'n8n Automation Agent',
  '3c88bb29-c1d9-4358-aa4c-50c32bccc8f4': 'Reporting Agent',
  'e895240c-8524-403a-8770-d095915d8302': 'DevOps Agent',
  '9819d4cb-e0b7-45d8-8e26-b257298aac79': 'Chief of Staff Agent',
  '876bad48-2bd7-4dd4-a429-6bf95f6a94f6': 'WhatsApp Business Agent',
  'b713f1b8-1b78-486c-b6ef-0fc2a885f2ec': 'CEO Agent'
};

const agentId = agentMap[agentAlias];
if (!agentId) {
  return [reply(`❌ *Agente no reconocido: "${agentAlias}"*
Por favor usa uno de los alias de ayuda.`)];
}

if (!instruction) {
  return [reply(`⚠️ *Falta la instrucción.*
Por favor escribe lo que el agente debe hacer.`)];
}

const shortInstruction = instruction.split('\n')[0].substring(0, 50) + (instruction.length > 50 ? '...' : '');
const title = `Telegram: ${shortInstruction}`;

return [{
  json: {
    action: 'create_issue',
    chatId,
    replyToMessageId: messageId,
    agentName: agentMapNames[agentId],
    agentId,
    title,
    description: instruction
  }
}];
